package travelcare_agent.evaluation.scoring; import org.springframework.stereotype.Component; @Component public class WorkflowOutcomeScorer implements EvaluationScorer {public String name(){return "workflowOutcome";} public ScoreResult score(EvaluationScoringContext c){var n=c.expectation()==null?null:c.expectation().get("expectedWorkflowStatus");if(n==null||n.isNull())return ScoreResult.skipped(name());String e=n.asText();boolean p=e.equals(c.workflowStatus());return ScoreResult.of(name(),p,e,c.workflowStatus(),p?"workflow status matched":"workflow status mismatch");}}
